@Aspect @Component
class LoggingAspect {

    // Pointcut — defines WHERE advice applies
    @Pointcut("execution(* com.app.service.*.*(..))")
    public void serviceMethods() {}

    @Before("serviceMethods()")              // runs BEFORE method
    public void logBefore(JoinPoint jp) {
        System.out.println("Calling: " + jp.getSignature());
    }

    @AfterReturning(pointcut="serviceMethods()", returning="result")
    public void logAfter(Object result) { // after success }

    @AfterThrowing(pointcut="serviceMethods()", throwing="ex")
    public void logException(Exception ex) { // after exception }

    @Around("serviceMethods()")             // wraps method (most powerful)
    public Object time(ProceedingJoinPoint pjp) throws Throwable {
        long start = System.currentTimeMillis();
        Object result = pjp.proceed();      // invoke actual method
        System.out.println("Time: " + (System.currentTimeMillis() - start) + "ms");
        return result;
    }
}

