// 4 States of a Hibernate Entity

// 1. TRANSIENT (New) — created with new, not associated with session
User u = new User(); u.setName("Alice");  // transient

// 2. PERSISTENT (Managed) — in session cache, tracked by Hibernate
session.persist(u);  // now persistent → changes auto-synced on commit
u.setEmail("a@b.com");  // dirty checking → UPDATE on commit

// 3. DETACHED — removed from session (session closed/clear/evict)
session.close();  // or: session.evict(u), session.detach(u), session.clear()
u.setName("Bob"); // NOT tracked, NOT updated in DB

// Re-attach: saveOrUpdate() or merge()
session.merge(u);  // copies state into new persistent instance

// 4. REMOVED — scheduled for deletion
session.remove(u);  // DELETE on commit

