// JWT structure: header.payload.signature
// eyJhbGciOiJIUzI1NiJ9  .  eyJzdWIiOiJ1c2VyMSJ9  .  [signature]
//      HEADER (base64)          PAYLOAD (base64)      HMAC-SHA256

// Header: algorithm + token type
// { "alg": "HS256", "typ": "JWT" }

// Payload (claims) — do NOT store passwords!
// { "sub": "user@email.com", "roles": ["ADMIN"], "exp": 1700000000 }

// Signature: HMAC(base64(header) + "." + base64(payload), secretKey)
// Tamper-proof: any modification breaks the signature

// JWT authentication flow:
// 1. POST /signin {email, password}
// 2. Server validates → generates JWT → returns to client
// 3. Client stores JWT (localStorage/cookie)
// 4. Each request: Authorization: Bearer eyJhbGc...
// 5. Server validates JWT signature → grants access

// Spring Security Filter Chain intercepts ALL requests BEFORE DispatcherServlet
// Filters run in sequence:

// 1. SecurityContextPersistenceFilter — load/save SecurityContext
// 2. UsernamePasswordAuthenticationFilter — handle POST /login
// 3. RememberMeAuthenticationFilter — remember-me cookie
// 4. AnonymousAuthenticationFilter — set anonymous user if no auth
// 5. AuthorizationFilter — check permissions, block if unauthorized
// 6. → DispatcherServlet → Controller

// Custom JWT Filter (before UsernamePasswordAuthenticationFilter)
@Component
class JwtRequestFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest req, ...) {
        String jwt = extractJwt(req.getHeader("Authorization"));
        if (jwtUtil.isValid(jwt)) {
            UserDetails user = userDetailsService.loadUserByUsername(jwtUtil.getEmail(jwt));
            UsernamePasswordAuthenticationToken auth =
                new UsernamePasswordAuthenticationToken(user, null, user.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(auth);
        }
        filterChain.doFilter(req, resp);
    }
}

// SIGN-IN FLOW (no auth required)
// POST /signin {email, password}
// → AuthController → AuthenticationManager.authenticate()
// → AuthenticationProvider → MyUserDetailsService.loadUserByUsername(email)
// → MyUserRepository.findByEmail() → UserDetails returned
// → AuthManager validates password via PasswordEncoder.matches()
// → generate JWT → return to client

// PROTECTED ENDPOINT FLOW
// GET /products  with  Authorization: Bearer <jwt>
// → JwtRequestFilter: extract jwt → validate → load UserDetails
// → set Authentication in SecurityContext
// → AuthorizationFilter: check roles/authorities
// → MyProductController if authorized → 200 OK
// → 403 Forbidden if not authorized

@Configuration @EnableWebSecurity
class SecurityConfig {
    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        return http
            .csrf(csrf -> csrf.disable())
            .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/signin", "/signup").permitAll()
                .requestMatchers("/admin/**").hasRole("ADMIN")
                .anyRequest().authenticated())
            .addFilterBefore(jwtFilter, UsernamePasswordAuthenticationFilter.class)
            .build();
    }
}

